// Validate HeyGen signature (HMAC-SHA256 of body using HEYGEN_WEBHOOK_SECRET).
// HeyGen signs via X-Heygen-Signature header. If secret is not configured, allow
// the request but mark _unverified=true (Mary should set the secret before going live).
const crypto = require('crypto');
const headers = $input.item.json.headers || {};
const body = $input.item.json.body || $input.item.json;
const rawBodyString = typeof body === 'string' ? body : JSON.stringify(body);
const sig = headers['x-heygen-signature'] || headers['X-Heygen-Signature'] || '';
const secret = process.env.HEYGEN_WEBHOOK_SECRET || '';
let verified = false;
let unverified = false;
if (secret && sig) {
  const computed = crypto.createHmac('sha256', secret).update(rawBodyString).digest('hex');
  verified = (computed === sig);
} else if (!secret) {
  unverified = true;   // allow but flag
  verified = true;
}
if (!verified) return { json: { _unauthorized: true, error: 'invalid signature' } };

// HeyGen v2 callback shape: { event_type: 'video.success', event_data: { callback_id, video_id, url, duration } }
const event = body.event_type || body.event || '';
const data = body.event_data || body.data || body;
const callbackId = data.callback_id || data.callbackId || null;       // = video_render_id
const heygenVideoId = data.video_id || data.videoId || null;
const sourceUrl = data.url || data.video_url || data.preview_url || null;
const durationSec = Math.round((data.duration || 0) || 0);
if (!callbackId || !sourceUrl) return { json: { _empty: true, error: 'missing callback_id or url', event: event } };
return { json: {
  _verified: true,
  _unverified_warning: unverified,
  video_render_id: callbackId,
  heygen_video_id: heygenVideoId,
  source_video_url: sourceUrl,
  duration_seconds: durationSec,
  event_type: event
} };

// Generate landing_page_token (16+ chars, URL-safe) and assemble final patch.
const crypto = require('crypto');
const ctx = $('Verify Signature').item.json;
const token = crypto.randomBytes(12).toString('base64').replace(/[+/=]/g, '').slice(0, 16);
const publicBase = process.env.R2_PUBLIC_URL || 'https://videos.crystallux.org';
const landingBase = process.env.LANDING_PAGE_BASE || 'https://crystallux.org/v';
return { json: {
  video_render_id: ctx.video_render_id,
  landing_page_token: token,
  landing_page_url: landingBase + '/' + token,
  storage_provider: 'cloudflare_r2',
  storage_key: 'videos/' + ctx.video_render_id + '.mp4',
  storage_url: publicBase + '/videos/' + ctx.video_render_id + '.mp4',
  duration_seconds: ctx.duration_seconds,
  status: 'ready',
  rendered_at: new Date().toISOString()
} };
